mapper.select:
SELECT b.*, ANY_VALUE(a.candidate_no) as candidate_no FROM xm_person_course_relate a LEFT JOIN xm_project b ON b.id = a.project_id WHERE b.is_delete=0 and a.is_delete=0 and b.train_way in(2,4) and a.person_id = #{personId} and a.if_join_exam = 0 and b.exam_edate > now()
and b.train_class =#{examClassify}
and b.project_status =#{status}
GROUP BY b.id

select a.id as questionId,a.question_type,b.topic_score,a.right_answers from xm_course_question a 
LEFT JOIN  xm_project_test_paper_tactics b ON a.question_type = b.topic_type 
where b.is_delete=0 and a.id in 

    #{item}

and b.project_id = #{projectId}

SELECT b.*, ifnull((select score from xm_answer_report a where a.person_id =c.person_id and a.is_delete = 0 and type=2 and project_id = b.id ORDER BY create_time limit 1),0) score, ifnull((select answer_time from xm_answer_report a where a.person_id =c.person_id and a.is_delete = 0 and type=2 and project_id = b.id ORDER BY create_time limit 1),0) examinationTime, ANY_VALUE(c.candidate_no) as candidate_no from xm_project b left join xm_person_course_relate c on c.project_id = b.id where b.is_delete = 0 and c.is_delete = 0 and b.train_way in (2, 4) and c.person_id = #{personId}
and b.train_class =#{examClassify}
and (b.id in (select a.project_id from xm_answer_report a where a.person_id =c.person_id and a.is_delete = 0 and type=2) or b.exam_edate < now()) GROUP BY b.id

SELECT b.* , if_join_exam, ifnull((select (count(1) < exam_number and max(ifnull(c.score,0)) < b.pass_score) from xm_answer_report c where c.type = 2 and if_attend = 1 and c.is_delete = 0 and c.person_id = a.person_id and c.project_id = b.id ),0) makeUpExam FROM xm_person_course_relate a LEFT JOIN xm_project b ON a.project_id = b.id WHERE a.is_delete = 0 and b.is_delete = 0 and b.train_way IN ( 2, 4 ) and a.person_id = #{personId} and a.learn_hours >= b.exam_open_condition
and b.train_class =#{examClassify}
and b.project_status =#{status}
